class Solution:
    def largestOddNumber(self, num):
        candidates = []
        for j in range(len(num)):
            if (ord(num[j]) - 48) % 2 == 1:
                candidates.append(num[:j + 1])
        if not candidates:
            return ''
        return max(candidates, key=lambda s: (len(s), s))

